//! Helpers for managing tasks generated by the handshake manager

use std::time::Duration;

use job_types::task_driver::TaskDriverJob;
use state::error::StateError;
use types_tasks::{QueuedTask, TaskDescriptor};

use crate::{error::MatchingEngineError, executor::MatchingEngineExecutor};

/// Max attempts to enqueue a serial preemptive settlement task while a
/// counterparty wallet queue transiently holds a committed task.
const PREEMPT_RETRY_MAX_ATTEMPTS: usize = 6;
/// Base backoff (ms) between preemption retries; doubled each attempt
/// (150, 300, 600, 1200, 2400) to outlast a just-placed order's commit window.
const PREEMPT_RETRY_BASE_BACKOFF_MS: u64 = 150;
/// Substring of the state-layer rejection raised when a serial preemption is
/// refused because a queue head task is committed
/// (state/.../task_queue/storage.rs::ERR_CANNOT_SERIALLY_PREEMPT).
const SERIAL_PREEMPTION_REJECTED: &str = "serial preemption not allowed";

impl MatchingEngineExecutor {
    /// Enqueue a serial task and await its completion
    pub async fn forward_queued_task(
        &self,
        descriptor: TaskDescriptor,
    ) -> Result<(), MatchingEngineError> {
        self.enqueue_task_await_completion(descriptor, false /* bypass_queue */).await
    }

    /// Enqueue a concurrent task and await its completion
    pub async fn forward_bypassing_task(
        &self,
        descriptor: TaskDescriptor,
    ) -> Result<(), MatchingEngineError> {
        self.enqueue_task_await_completion(descriptor, true /* bypass_queue */).await
    }

    /// Enqueue a task and await its completion
    async fn enqueue_task_await_completion(
        &self,
        descriptor: TaskDescriptor,
        bypass_queue: bool,
    ) -> Result<(), MatchingEngineError> {
        if bypass_queue {
            self.send_task_to_driver(descriptor).await
        } else {
            self.enqueue_task_through_raft(descriptor).await
        }
    }

    /// Enqueue a task through the raft task queue abstraction
    ///
    /// Internal/private match settlement is the only caller (see
    /// `internal_engine::try_settle_match`); it enqueues a SERIAL PREEMPTIVE task
    /// on both counterparties' wallet queues. If a counterparty's queue head is a
    /// *committed* order-management task — e.g. the order the taker just placed,
    /// which triggered this very match — the preemption is rejected with
    /// "serial preemption not allowed". That task is transient (~1s commit
    /// window), so rather than drop the fill we retry the enqueue with bounded
    /// exponential backoff that outlasts the commit window.
    async fn enqueue_task_through_raft(
        &self,
        descriptor: TaskDescriptor,
    ) -> Result<(), MatchingEngineError> {
        let accounts = descriptor.affected_accounts();

        let mut attempt = 0;
        let (tid, waiter) = loop {
            match self
                .state
                .enqueue_preemptive_task(
                    accounts.clone(),
                    descriptor.clone(),
                    true, /* is_serial */
                )
                .await
            {
                Ok(res) => break res,
                Err(StateError::TransitionRejected(msg))
                    if msg.contains(SERIAL_PREEMPTION_REJECTED)
                        && attempt + 1 < PREEMPT_RETRY_MAX_ATTEMPTS =>
                {
                    let backoff_ms = PREEMPT_RETRY_BASE_BACKOFF_MS << attempt;
                    tracing::debug!(
                        attempt = attempt + 1,
                        backoff_ms,
                        "serial preemption rejected (counterparty queue busy); retrying settle enqueue"
                    );
                    tokio::time::sleep(Duration::from_millis(backoff_ms)).await;
                    attempt += 1;
                },
                Err(e) => return Err(e.into()),
            }
        };
        waiter.await?;

        // Await a completion notification from the task driver
        let (job, rx) = TaskDriverJob::new_notification(tid);
        self.task_queue.send(job).map_err(MatchingEngineError::send_message)?;
        rx.await
            .map_err(MatchingEngineError::task)? // RecvError
            .map_err(MatchingEngineError::task) // TaskDriverError
    }

    /// Enqueue a task directly to the task driver
    async fn send_task_to_driver(
        &self,
        descriptor: TaskDescriptor,
    ) -> Result<(), MatchingEngineError> {
        // Send the task to the task driver
        let queued = QueuedTask::new(descriptor);
        let (job, rx) = TaskDriverJob::run_with_notification(queued);
        self.task_queue.send(job).map_err(MatchingEngineError::send_message)?;

        // Await a completion notification from the task driver
        rx.await
            .map_err(MatchingEngineError::task)? // RecvError
            .map_err(MatchingEngineError::task) // TaskDriverError
    }
}
